def cached(ttl=None, key_prefix=None, key_func=None):
    """
    Decorator to cache function results.
    
    Args:
        ttl: Time-to-live in seconds
        key_prefix: Prefix for the cache key
        key_func: Custom function to generate cache key from request
    """
    def decorator(f):
        @wraps(f)
        def decorated_function(*args, **kwargs):
            # Generate cache key
            if key_func:
                cache_key = key_func(*args, **kwargs)
            else:
                prefix = key_prefix or f.__name__
                # Include request path and query params in key
                request_data = f"{request.path}:{request.query_string.decode('utf-8')}"
                cache_key = f"{prefix}:{request_data}"

            # Try to get from cache
            cached_result = cache_get(cache_key)
            if cached_result is not None:
                response = jsonify(cached_result)
                response.headers['X-Cache'] = 'HIT'
                return response

            # Execute function and cache result
            result = f(*args, **kwargs)

            # Only cache successful responses
            if isinstance(result, tuple):
                response_data, status_code = result[0], result[1] if len(result) > 1 else 200
            else:
                response_data = result
                status_code = 200

            if status_code == 200:
                # Extract JSON-serializable data
                if hasattr(response_data, 'get_json'):
                    data_to_cache = response_data.get_json()
                elif isinstance(response_data, dict):
                    data_to_cache = response_data
                else:
                    data_to_cache = response_data

                effective_ttl = ttl or app.config['DEFAULT_CACHE_TTL']
                cache_set(cache_key, data_to_cache, ttl=effective_ttl)

            if isinstance(response_data, dict):
                response = jsonify(response_data)
                response.headers['X-Cache'] = 'MISS'
                if isinstance(result, tuple) and len(result) > 1:
                    return response, result[1]
                return response

            return result

        return decorated_function
    return decorator


