def rate_limit(max_requests=60, window_seconds=60):
    """
    Rate limiting decorator using Memcached.
    Prevents abuse of the API.
    """
    def decorator(f):
        @wraps(f)
        def decorated_function(*args, **kwargs):
            # Use IP address for rate limiting
            client_ip = request.remote_addr or 'unknown'
            rate_key = f"ratelimit:{f.__name__}:{client_ip}"

            try:
                client = get_cache_client()
                safe_key = _make_safe_cache_key(rate_key)

                current = client.get(safe_key)
                if current is None:
                    # First request in window
                    client.set(safe_key, {'count': 1, 'window_start': time.time()}, expire=window_seconds)
                else:
                    if isinstance(current, dict) and current.get('count', 0) >= max_requests:
                        return jsonify({
                            'error': 'Rate limit exceeded',
                            'retry_after': window_seconds
                        }), 429
                    # Increment counter
                    new_count = (current.get('count', 0) if isinstance(current, dict) else 0) + 1
                    remaining_ttl = window_seconds  # Simplified; in production use CAS
                    client.set(safe_key, {
                        'count': new_count,
                        'window_start': current.get('window_start', time.time()) if isinstance(current, dict) else time.time()
                    }, expire=remaining_ttl)
            except Exception as e:
                # If rate limiting fails, allow the request but log the error
                app.logger.error(f"Rate limiting error: {_sanitize_log(str(e))}")

            return f(*args, **kwargs)
        return decorated_function
    return decorator


# --- Input Validation ---

def validate_positive_int(value, param_name):
    """Validate that a parameter is a positive integer."""
    try:
        int_val = int(value)
        if int_val <= 0:
            abort(400, description=f"Parameter '{param_name}' must be a positive integer")
        if int_val > 2**31:
            abort(400, description=f"Parameter '{param_name}' is too large")
        return int_val
    except (ValueError, TypeError):
        abort(400, description=f"Parameter '{param_name}' must be a valid integer")


def validate_search_query(query):
    """Validate and sanitize search query."""
    if not query or not isinstance(query, str):
        abort(400, description="Search query is required")
    # Limit length
    if len(query) > 200:
        abort(400, description="Search query too long (max 200 characters)")
    # Basic sanitization - strip control characters
    sanitized = ''.join(c for c in query if c.isprintable())
    if not sanitized:
        abort(400, description="Search query contains only invalid characters")
    return sanitized


